    let query = supabase
        .from('sops')
        .select('id, sop_number, trade_code, trade_name, task_name, revision, status, estimated_duration, trade_id')
        .eq('status', 'active')
        .order('trade_code')
        .order('sop_number');

    if (tradeId) query = query.eq('trade_id', tradeId);
    if (tradeCode) query = query.eq('trade_code', tradeCode);

    const { data, error } = await query;
    if (error) return c.json({ error: error.message }, 500);
    return c.json(data || []);
});

